//! Bundled single-page chat UI for the Forge MVP.

pub const CHAT_HTML: &str = r#"<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Forge Unified</title>
  <style>
    :root{color-scheme:dark;--bg:#0b1020;--panel:#111a2e;--panel2:#18233a;--text:#edf4ff;--muted:#9fb0d0;--border:#2a3858;--accent:#67e8f9;--danger:#fb7185;--ok:#86efac;--warn:#fde68a;--add:#86efac;--edit:#67e8f9;--del:#fb7185;--move:#fde68a}
    *{box-sizing:border-box}body{margin:0;min-height:100vh;background:radial-gradient(circle at top left,#1e3a5f 0,var(--bg) 42rem);color:var(--text);font:15px/1.45 system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}button,textarea{font:inherit}button{border:1px solid var(--border);background:var(--panel2);color:var(--text);border-radius:12px;padding:.65rem .9rem;cursor:pointer}button.primary{background:var(--accent);color:#04111f;border-color:transparent;font-weight:800}button:disabled{opacity:.55;cursor:not-allowed}.app{display:grid;grid-template-columns:minmax(240px,320px) minmax(0,1fr);min-height:100vh}aside{border-right:1px solid var(--border);background:rgba(17,26,46,.88);padding:1rem;display:flex;flex-direction:column;gap:1rem}main{min-width:0;display:grid;grid-template-rows:auto 1fr auto;min-height:100vh}.brand{display:flex;justify-content:space-between;gap:1rem;align-items:start}h1{font-size:1.2rem;margin:0}.subtitle{color:var(--muted);font-size:.86rem;margin-top:.25rem}.pill{display:inline-flex;align-items:center;padding:.25rem .55rem;border:1px solid var(--border);border-radius:999px;color:var(--muted);font-size:.78rem;white-space:nowrap}.status-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:.55rem}.metric{background:rgba(24,35,58,.82);border:1px solid var(--border);border-radius:14px;padding:.75rem}.metric strong{display:block;font-size:1.2rem}.metric span{color:var(--muted);font-size:.78rem}.conv-list{display:flex;flex-direction:column;gap:.45rem;overflow:auto}.conv{text-align:left;width:100%;border-radius:14px;padding:.75rem}.conv.active{border-color:var(--accent);box-shadow:0 0 0 1px rgba(103,232,249,.25) inset}.conv-title{font-weight:800;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.conv-meta{color:var(--muted);font-size:.78rem;margin-top:.2rem}.topbar{border-bottom:1px solid var(--border);padding:1rem clamp(1rem,3vw,1.5rem);display:flex;justify-content:space-between;gap:1rem;align-items:center;background:rgba(11,16,32,.66)}.chat-title{font-size:1rem;font-weight:800}.actions{display:flex;flex-wrap:wrap;gap:.5rem;justify-content:end}.messages{padding:1rem clamp(1rem,3vw,1.5rem);overflow:auto;display:flex;flex-direction:column;gap:.8rem}.empty{margin:auto;max-width:760px;border:1px solid var(--border);background:rgba(17,26,46,.82);border-radius:24px;padding:1.5rem}.message{max-width:920px;border:1px solid var(--border);border-radius:18px;padding:.9rem;background:rgba(17,26,46,.82);white-space:pre-wrap;overflow-wrap:anywhere}.message.user{align-self:flex-end;background:rgba(103,232,249,.13);border-color:rgba(103,232,249,.42)}.message.assistant{align-self:flex-start}.message.tool{align-self:stretch;max-width:none;background:rgba(24,35,58,.72)}.role{display:flex;justify-content:space-between;color:var(--muted);font-size:.78rem;margin-bottom:.45rem;text-transform:uppercase;letter-spacing:.04em}.tool-card{border:1px solid var(--border);border-radius:14px;padding:.75rem;margin-top:.5rem;background:rgba(0,0,0,.16)}.tool-head{display:flex;justify-content:space-between;gap:1rem;color:var(--accent);font-weight:800}.tool-card.ok .tool-head{color:var(--ok)}.tool-card.err .tool-head{color:var(--danger)}.tool-card.subagent{border-color:rgba(103,232,249,.55)}.tool-card.parallel{border-style:dashed}.tool-card pre{margin:.65rem 0 0;padding:.8rem;border-radius:12px;background:#050914;overflow:auto;max-height:18rem;color:#d9e7ff}.file-events{display:grid;gap:.45rem;margin-top:.65rem}.file-card{border:1px solid var(--border);border-radius:12px;background:rgba(5,9,20,.72);padding:.65rem;display:grid;gap:.35rem}.file-card.add{border-color:rgba(134,239,172,.5)}.file-card.edit{border-color:rgba(103,232,249,.5)}.file-card.delete{border-color:rgba(251,113,133,.55)}.file-card.move{border-color:rgba(253,230,138,.55)}.file-title{display:flex;align-items:center;gap:.5rem;font-weight:800}.file-badge{display:inline-flex;align-items:center;justify-content:center;min-width:2rem;border-radius:999px;padding:.12rem .45rem;background:rgba(255,255,255,.08);font-size:.75rem}.file-path{font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;overflow-wrap:anywhere}.file-meta{color:var(--muted);font-size:.78rem}.file-card.add .file-badge{color:var(--add)}.file-card.edit .file-badge{color:var(--edit)}.file-card.delete .file-badge{color:var(--del)}.file-card.move .file-badge{color:var(--move)}.composer{border-top:1px solid var(--border);padding:1rem clamp(1rem,3vw,1.5rem);background:rgba(11,16,32,.88)}.composer-inner{display:grid;grid-template-columns:1fr auto;gap:.75rem;align-items:end}textarea{width:100%;min-height:4.5rem;max-height:12rem;resize:vertical;border-radius:16px;border:1px solid var(--border);color:var(--text);background:rgba(17,26,46,.92);padding:.85rem}.hint{color:var(--muted);font-size:.8rem;margin-top:.45rem}.toast{position:fixed;right:1rem;bottom:1rem;max-width:min(36rem,calc(100vw - 2rem));background:#09111f;border:1px solid var(--border);border-radius:16px;padding:.8rem .9rem;color:var(--text);box-shadow:0 18px 60px rgba(0,0,0,.35);display:none;z-index:20}.toast.show{display:block}.error{color:var(--danger)}.ok{color:var(--ok)}@media(max-width:780px){.app{grid-template-columns:1fr}aside{border-right:0;border-bottom:1px solid var(--border);max-height:38vh}main{min-height:62vh}.composer-inner{grid-template-columns:1fr}.actions{justify-content:start}}
  </style>
</head>
<body>
  <div class="app"><aside><div class="brand"><div><h1>Forge Unified</h1><div class="subtitle">Chat-first coding app MVP.</div></div><span class="pill" id="health-pill">checking</span></div><button id="new-conversation" class="primary" type="button">New conversation</button><div class="status-grid"><div class="metric"><strong id="conversation-count">0</strong><span>conversations</span></div><div class="metric"><strong id="message-count">0</strong><span>messages</span></div></div><div class="conv-list" id="conversation-list"></div></aside><main><div class="topbar"><div><div class="chat-title" id="chat-title">No conversation selected</div><div class="subtitle" id="chat-subtitle">Persistent chat id appears here.</div></div><div class="actions"><button id="refresh" type="button">Refresh</button><button id="snapshot" type="button" disabled>Save snapshot</button><button id="graph" type="button">Graph</button></div></div><section class="messages" id="messages" aria-live="polite"></section><div class="composer"><div class="composer-inner"><label><span class="subtitle">Message</span><textarea id="message-input" placeholder="Ask Forge to inspect files, plan a change, use parallel tools, or spawn a subagent task." disabled></textarea></label><button id="send" class="primary" type="button" disabled>Send</button></div><div class="hint">Enter sends. SSE events stream run phases, text deltas, tool calls, tool results, file change cards, subagent cards, and parallel batch cards.</div></div></main></div><div class="toast" id="toast" role="status" aria-live="polite"></div>
  <script>
    const state={conversations:[],activeId:null,activeConversation:null,busy:false,streamAssistant:null};const $=id=>document.getElementById(id);
    function toast(message,kind=''){const el=$('toast');el.textContent=message;el.className='toast show '+kind;clearTimeout(toast.timer);toast.timer=setTimeout(()=>el.className='toast',4500)}
    async function api(path,options={}){const response=await fetch(path,{headers:{'content-type':'application/json',...(options.headers||{})},...options});const text=await response.text();let data=null;try{data=text?JSON.parse(text):null}catch{data=text}if(!response.ok)throw new Error(`${response.status} ${response.statusText}: ${typeof data==='string'?data:JSON.stringify(data)}`);return data}
    async function checkHealth(){try{const h=await api('/api/health');$('health-pill').textContent=h.status||'ok';$('health-pill').classList.add('ok')}catch{$('health-pill').textContent='offline';$('health-pill').classList.add('error')}}
    async function loadConversations(selectFirst=false){state.conversations=await api('/api/conversations');$('conversation-count').textContent=String(state.conversations.length);renderConversationList();if(!state.activeId&&selectFirst&&state.conversations.length)await selectConversation(state.conversations[0].id)}
    function renderConversationList(){const list=$('conversation-list');list.innerHTML='';for(const conv of state.conversations){const b=document.createElement('button');b.type='button';b.className='conv'+(conv.id===state.activeId?' active':'');b.innerHTML='<div class="conv-title"></div><div class="conv-meta"></div>';b.querySelector('.conv-title').textContent=conv.title||'Untitled';b.querySelector('.conv-meta').textContent=`${conv.message_count} messages · ${conv.mode}`;b.addEventListener('click',()=>selectConversation(conv.id));list.appendChild(b)}}
    async function createConversation(){const created=await api('/api/conversations',{method:'POST',body:JSON.stringify({title:`Forge run ${new Date().toLocaleString()}`})});state.activeId=created.id;await loadConversations(false);await selectConversation(created.id);toast('Conversation created','ok')}
    async function selectConversation(id){state.activeId=id;state.activeConversation=await api(`/api/conversations/${encodeURIComponent(id)}`);$('chat-title').textContent=state.activeConversation.title||'Untitled';$('chat-subtitle').textContent=id;$('message-input').disabled=false;$('send').disabled=state.busy;$('snapshot').disabled=false;$('message-count').textContent=String((state.activeConversation.messages||[]).length);renderConversationList();renderMessages()}
    function renderMessages(){const c=$('messages');c.innerHTML='';const messages=state.activeConversation?.messages||[];if(!messages.length){c.innerHTML='<div class="empty"><h2>Ready to build</h2><p>Ask Forge to inspect files, edit code, use parallel tools, or make a plan. Live run events will appear here.</p></div>';return}for(const msg of messages)c.appendChild(renderMessage(msg));c.scrollTop=c.scrollHeight}
    function renderMessage(msg){const a=document.createElement('article');const role=(msg.role||'unknown').toLowerCase();a.className=`message ${role}`;a.innerHTML='<div class="role"><span></span><span></span></div>';a.querySelector('.role span').textContent=role;if(msg.content){const body=document.createElement('div');body.textContent=msg.content;a.appendChild(body)}const allEvents=[];for(const res of msg.tool_results||[])for(const ev of res?.metadata?.file_events||[])allEvents.push(ev);if(allEvents.length)a.appendChild(fileEventsBlock(allEvents));for(const call of msg.tool_calls||[])a.appendChild(toolCard('called',call.kind||'tool',call,false));for(const res of msg.tool_results||[])a.appendChild(toolCard(res.success?'done':'failed',res.kind||'tool',res,true));return a}
    function toolCard(status,name,payload,finished){const card=document.createElement('div');const kind=String(name);card.className='tool-card '+(finished?(payload.success?'ok':'err'):'')+(kind==='Task'?' subagent':'')+(kind==='BatchParallel'?' parallel':'');card.innerHTML='<div class="tool-head"><span></span><span></span></div>';card.querySelector('.tool-head span').textContent=(kind==='Task'?'subagent':kind==='BatchParallel'?'parallel':kind);card.querySelector('.tool-head span:last-child').textContent=status;const events=payload?.metadata?.file_events||[];if(events.length)card.appendChild(fileEventsBlock(events));const pre=document.createElement('pre');pre.textContent=JSON.stringify(payload,null,2);card.appendChild(pre);return card}
    function fileEventsBlock(events){const wrap=document.createElement('div');wrap.className='file-events';for(const ev of events)wrap.appendChild(fileEventCard(ev));return wrap}
    function fileEventCard(ev){const type=String(ev.type||'file.edited');const short=type.replace('file.','');const cls=short==='added'?'add':short==='deleted'?'delete':short==='moved'?'move':'edit';const card=document.createElement('div');card.className='file-card '+cls;const title=document.createElement('div');title.className='file-title';const badge=document.createElement('span');badge.className='file-badge';badge.textContent=short.toUpperCase();const path=document.createElement('span');path.className='file-path';path.textContent=ev.previousPath&&ev.path?`${ev.previousPath} → ${ev.path}`:(ev.path||'unknown file');title.appendChild(badge);title.appendChild(path);const meta=document.createElement('div');meta.className='file-meta';meta.textContent=`+${ev.additions||0} / -${ev.deletions||0}${ev.bom?' · BOM':''}${ev.source?' · '+ev.source:''}`;card.appendChild(title);card.appendChild(meta);return card}
    function appendUser(text){const a=document.createElement('article');a.className='message user';a.innerHTML='<div class="role"><span>user</span><span>stream</span></div>';const b=document.createElement('div');b.textContent=text;a.appendChild(b);$('messages').appendChild(a)}
    function ensureAssistant(){if(state.streamAssistant)return state.streamAssistant;const a=document.createElement('article');a.className='message assistant';a.innerHTML='<div class="role"><span>assistant</span><span>SSE</span></div><div class="stream-text"></div>';$('messages').appendChild(a);state.streamAssistant=a.querySelector('.stream-text');return state.streamAssistant}
    function handleEvent(name,data){if(name==='run-start')toast('Run started');else if(name==='text-delta')ensureAssistant().textContent+=data.text||'';else if(name==='tool-call')$('messages').appendChild(toolCard('running',data.kind||data.name||'tool',data,false));else if(name==='tool-result'||name==='tool-error')$('messages').appendChild(toolCard(name==='tool-result'?'done':'failed',data.kind||data.name||'tool',data,true));else if(name==='file-change')$('messages').appendChild(fileEventCard(data));else if(name==='provider-error')toast(data.message||'provider error','error');else if(name==='conversation'){state.activeConversation=data;$('message-count').textContent=String((data.messages||[]).length)}else if(name==='run-finish')toast('Run finished','ok');$('messages').scrollTop=$('messages').scrollHeight}
    async function readSse(response){const reader=response.body.getReader();const decoder=new TextDecoder();let buffer='';while(true){const {value,done}=await reader.read();if(done)break;buffer+=decoder.decode(value,{stream:true});let parts=buffer.split('\n\n');buffer=parts.pop();for(const part of parts){let event='message',data='';for(const line of part.split('\n')){if(line.startsWith('event:'))event=line.slice(6).trim();if(line.startsWith('data:'))data+=line.slice(5).trim()}try{handleEvent(event,data?JSON.parse(data):{})}catch(e){toast(e.message,'error')}}}}
    async function sendMessage(){const input=$('message-input');const message=input.value.trim();if(!state.activeId||!message||state.busy)return;state.busy=true;state.streamAssistant=null;input.value='';$('send').disabled=true;input.disabled=true;if(!$('messages').children.length)$('messages').innerHTML='';appendUser(message);try{const response=await fetch(`/api/conversations/${encodeURIComponent(state.activeId)}/chat/stream`,{method:'POST',headers:{'content-type':'application/json','accept':'text/event-stream'},body:JSON.stringify({message,max_rounds:10})});if(!response.ok)throw new Error(`stream failed ${response.status}`);await readSse(response);await selectConversation(state.activeId);await loadConversations(false)}catch(err){toast(err.message,'error')}finally{state.busy=false;input.disabled=!state.activeId;$('send').disabled=!state.activeId}}
    async function saveSnapshot(){if(!state.activeId)return;await api(`/api/conversations/${encodeURIComponent(state.activeId)}/snapshot`,{method:'POST',body:'{}'});toast('Snapshot saved','ok')}
    $('new-conversation').addEventListener('click',()=>createConversation().catch(e=>toast(e.message,'error')));$('refresh').addEventListener('click',()=>Promise.all([loadConversations(false),state.activeId?selectConversation(state.activeId):null]).catch(e=>toast(e.message,'error')));$('snapshot').addEventListener('click',()=>saveSnapshot().catch(e=>toast(e.message,'error')));$('graph').addEventListener('click',()=>{window.location.href='/api/graph'});$('send').addEventListener('click',()=>sendMessage());$('message-input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendMessage()}});checkHealth();loadConversations(true).catch(e=>toast(e.message,'error'));
  </script>
</body>
</html>"#;
